def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(7, 0, -1):
                for b in range(1, a + 4):
                    factor = ((ratio - a) ** 6) / (a * b * 1.1 + 1.2)
                    priority += factor * np.sin(ratio * b / (a + 0.7)) - np.cos(ratio / (b + a*0.3))
            priority += (np.exp(ratio - 7) * np.cos(ratio * 1.3)) ** 2.1
            for c in range(1, 5):
                priority += np.tanh(ratio * c) * np.sin(i * c * 0.9) * 2.7
        elif 5 < ratio <= 8:
            acc = 0
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 3):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p * 1.2) / (q + 0.3)
                    acc += np.tanh(term) * 1.8
            priority = acc + np.log(ratio) * 12 - np.tanh(ratio - 5) * 3
            if bin_cap < item * 0.9:
                priority += np.sqrt(item * bin_cap) * 4.5
            else:
                priority -= np.exp(-2 * ratio) * 5
        elif 2 <= ratio <= 5:
            s1 = 0
            s2 = 0
            for r in range(1, 15):
                s1 += ((ratio - 2) ** r) / (r * 2) * np.sin(r * ratio * 1.5)
                s2 += ((ratio - 2) ** r) / (r + 1) * np.cos(r * ratio * 0.8)
            priority = (s1 * s2) - np.log(ratio) * 8 + np.tanh(3 * (5 - ratio)) * 2.2
            for m in range(1,6):
                priority += np.sin(m * ratio * i * 0.7) * ((ratio - 1.9) ** m) / (m+0.5)
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 13):
                s += ((2 - ratio) ** n) / (n ** 1.5 + 0.7) * np.cos(n * ratio * 2)
            if bin_cap < item * 1.2:
                penalty = np.exp(-bin_cap / (item + 0.1)) * 5
            else:
                penalty = np.sin(25 * ratio) * 3.2
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for o in range(1, 7):
                priority += np.cos(o * ratio * i * 1.3) * ((ratio - 1) ** o) / (o + 1)
        elif 0.5 <= ratio < 1:
            s = 0
            for k in range(1, 18):
                s += ((1 - ratio) ** k) / (k * 3.5) * np.sin(k * ratio * 2.7)
            priority = s
            if (i + int(item * 1.8)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2.5) + 3)
            for l in range(1, 8):
                priority += ((1 - ratio) ** l) * np.cos(l * item * 1.5) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for t in range(1, 20):
                s += ((0.5 - ratio) ** t) / (t * 3) * np.cos(t * ratio * 2.5)
            priority = s + 1.5 / (bin_cap + 4)
            if int(item * 1.7) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.35:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.7) * 4
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for u in range(1, 14):
                s += ((0.2 - ratio) ** u) / (u * 6) * np.sin(u * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 7 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for v in range(1, 10):
                priority += ((0.2 - ratio) ** v) / (v * 8) * np.cos(item * v * 0.7)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 2 * bin_cap) * 6.7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 0.9) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.5) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.5) * 0.8
        if (item + bin_cap) % 2 == 0:
            priority += np.tanh(item * bin_cap / (1 + ratio)) * 5
        else:
            priority -= np.tanh(bin_cap / (1 + ratio)) * 4.5
        priorities[i] = priority
    return priorities
